package main

import (
	"math"
)

func solve(nums []int64, k int64) int64 {
	n := len(nums)
	if n == 0 {
		return 0
	}

	total := int64(0)
	for i := 0; i < n; i++ {
		total += nums[i]
	}

	T := make([]int64, n+1)
	dp := make([]int64, n)

	best := make(map[int]int64)
	best[0] = 0

	T[0] = 0
	for i := 0; i < n; i++ {
		T[i+1] = T[i] + nums[i]
		r_val := T[i+1] % k
		r_int := int(r_val)

		candidate := int64(math.MinInt64)
		if val, ok := best[r_int]; ok {
			candidate = T[i+1] + val
		}

		if i == 0 {
			if candidate > math.MinInt64 {
				dp[i] = candidate
			} else {
				dp[i] = 0
			}
		} else {
			if candidate > dp[i-1] {
				dp[i] = candidate
			} else {
				dp[i] = dp[i-1]
			}
		}

		F := dp[i] - T[i+1]
		if val, ok := best[r_int]; ok {
			if F > val {
				best[r_int] = F
			}
		} else {
			best[r_int] = F
		}
	}

	residual := total - dp[n-1]
	return residual
}
```

### Explanation
1. **Initialization**: The function starts by checking if the array is empty. If so, it returns 0 as the residual sum. Otherwise, it computes the total sum of the array elements.
2. **Prefix Sum Array (T)**: The array `T` is constructed such that `T[i]` is the sum of the first `i` elements of the input array.
3. **Dynamic Processing**: For each element in the array:
   - The current prefix sum modulo `k` is computed to determine the residue.
   - A candidate value is derived using the best value from the map corresponding to the current residue. This candidate represents the maximum removable sum ending at the current position.
   - The DP array is updated to either include the candidate value or retain the previous maximum.
   - The map is updated to store the best value of `(dp[i] - T[i+1])` for the current residue.
4. **Result Calculation**: The residual sum is computed as the total array sum minus the maximum removable sum stored in the last position of the DP array. This value is returned as the result.

This approach efficiently maximizes the sum of removable subarrays, ensuring the minimal residual sum of the remaining contiguous segment in the array. The complexity is linear, making it suitable for large input sizes.
